parameters.jsCode:
const item = $input.item.json;
const raw = (item.body && item.body.message && item.body.message.text) || '';
const sender = (item.body && item.body.sender) || 'unknown';

// PII scrubber
const patterns = {
  cpf: /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g,
  rg: /\b\d{1,2}\.?\d{3}\.?\d{3}-?\d{1}\b/g,
  phone: /\b\(\d{2}\)\s?9?\d{4}-?\d{4}\b/g,
  email: /\b[\w.-]+@[\w.-]+\.\w+\b/g
};
let scrubbed = raw;
let redactionCount = 0;
for (const [type, pattern] of Object.entries(patterns)) {
  const matches = scrubbed.match(pattern);
  if (matches) {
    redactionCount += matches.length;
    scrubbed = scrubbed.replace(pattern, `[${type.toUpperCase()}_REDACTED]`);
  }
}

// Detectar dia/horario pedido (regex simples)
const diaMatch = scrubbed.match(/\b(segunda|terca|ter[\u00e7c]a|quarta|quinta|sexta|s[\u00e1a]bado|sabado)\b/i);
const horaMatch = scrubbed.match(/\b(\d{1,2})[h:](\d{2})?\b/i);

return { json: {
  sender, raw, scrubbed, redactionCount,
  dia: diaMatch ? diaMatch[1].toLowerCase() : null,
  hora: horaMatch ? parseInt(horaMatch[1]) : null,
  needsHandoff: redactionCount > 0 || (!diaMatch && !horaMatch)
}};

